        {/* Action Footer */}
        <div className="p-8 pt-0 mt-auto">
          <button 
            onClick={() => { onTrigger(); onClose(); }}
            className="w-full py-4 bg-navy-900 dark:bg-blue-600 text-white rounded-2xl font-bold flex items-center justify-center gap-2 shadow-xl shadow-blue-500/10 hover:scale-[1.02] active:scale-[0.98] transition-all"
          >
            {historyData[historyData.length - 1]?.status === 1 ? <Icons.RotateCcw size={18} /> : <Icons.Zap size={18} />}
            {historyData[historyData.length - 1]?.status === 1 ? 'Update Status' : 'Execute Core Action'}
          </button>
