       <div className={`p-2 rounded-lg ${active ? 'bg-blue-500 text-white' : 'bg-white/50 dark:bg-dark-cardHover text-slate-400'}`}>
          <Icon size={16} />
       </div>
       <span className={`text-sm font-semibold ${active ? 'text-blue-700 dark:text-blue-400' : 'text-slate-600 dark:text-slate-400'}`}>{name}</span>
