                        <button onClick={clearFilters} className="mt-4 text-xs font-bold text-navy-900 dark:text-blue-500 underline">Clear Filters</button>
                     )}
                  </div>
               )}
            </div>
         </div>
      </div>

      {/* UNDO NOTIFICATION (Liquid Glass Toast) */}
      {isUndoVisible && lastDeletedTask && (
        <div className="fixed bottom-10 left-1/2 -translate-x-1/2 z-[100] animate-fade-in-up">
            <div className="bg-navy-900/80 dark:bg-dark-card/90 backdrop-blur-2xl px-6 py-4 rounded-[1.5rem] shadow-2xl border border-white/20 dark:border-dark-border flex items-center gap-6 min-w-[320px]">
                <div className="flex items-center gap-3">
                    <div className="w-10 h-10 bg-white/10 rounded-full flex items-center justify-center text-white">
                        <Trash2 size={18} />
                    </div>
                    <div>
                        <p className="text-white text-sm font-bold truncate max-w-[150px]">Task Removed</p>
                        <p className="text-white/50 text-[10px] font-bold uppercase tracking-widest">Finalizing in 5s...</p>
                    </div>
                </div>
                <button 
                    onClick={handleUndo}
                    className="ml-auto flex items-center gap-2 bg-white text-navy-900 px-4 py-2 rounded-xl text-xs font-black uppercase tracking-wider hover:bg-slate-100 transition-all active:scale-95 shadow-lg"
                >
                    <RotateCcw size={14} /> Undo
                </button>
            </div>
        </div>
      )}

      {showTaskModal && <AddTaskModal onClose={() => setShowTaskModal(false)} />}
    </div>
  );
}

import React, { useState } from 'react';
import { useApp } from '../App';
import { Task, Priority, ReminderType } from '../types';
import { formatDate } from '../utils';
import { X, Bell, ListCheck, Paperclip, Plus, Trash2, Link, StickyNote } from 'lucide-react';

export default function AddTaskModal({ onClose }: { onClose: () => void }) {
  const { addTask, projects } = useApp();
  const [formData, setFormData] = useState<Partial<Task>>({
    title: '',
    description: '',
    notes: '',
    dueDate: formatDate(new Date()),
    priority: Priority.MEDIUM,
    category: 'General',
    reminder: { type: ReminderType.AT_DEADLINE }
  });

  // Subtasks State
  const [subtasks, setSubtasks] = useState<{ id: string; title: string; completed: boolean }[]>([]);
  const [newSubtask, setNewSubtask] = useState('');

  // Attachments State
  const [attachment, setAttachment] = useState('');

  const addSubtask = () => {
    if (!newSubtask.trim()) return;
    setSubtasks([...subtasks, { id: Date.now().toString() + Math.random(), title: newSubtask, completed: false }]);
    setNewSubtask('');
  };

  const removeSubtask = (id: string) => {
    setSubtasks(subtasks.filter(s => s.id !== id));
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.title) return;

    await addTask({
      id: `task_${Date.now()}`,
      title: formData.title,
      description: formData.description || '',
      notes: formData.notes || '',
      dueDate: formData.dueDate!,
      priority: formData.priority as Priority,
      category: formData.category || 'General',
      projectId: formData.projectId,
      completed: false,
      reminder: formData.reminder,
      subtasks: subtasks,
      attachments: attachment ? [attachment] : []
    } as Task);
    onClose();
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-navy-900/40 backdrop-blur-sm animate-fade-in">
      <div className="bg-white rounded-3xl w-full max-w-md p-6 shadow-2xl overflow-y-auto max-h-[90vh] custom-scrollbar">
        <div className="flex justify-between items-center mb-6">
          <h3 className="text-xl font-bold text-navy-900">New Task</h3>
          <button onClick={onClose} className="p-1 rounded-full hover:bg-slate-100 transition-colors">
            <X className="text-slate-400" size={20} />
          </button>
        </div>
        <form onSubmit={handleSubmit} className="space-y-4">
          <input 
            className="w-full text-lg font-semibold placeholder:text-slate-300 border-none focus:ring-0 p-0 text-navy-900"
            placeholder="What needs to be done?"
            value={formData.title}
            onChange={e => setFormData({...formData, title: e.target.value})}
            autoFocus
          />
          <textarea 
            className="w-full text-sm text-slate-600 placeholder:text-slate-300 border-none focus:ring-0 p-0 resize-none h-16"
            placeholder="Add brief description..."
            value={formData.description}
            onChange={e => setFormData({...formData, description: e.target.value})}
          />

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="text-xs font-bold text-slate-400 uppercase">Due Date</label>
              <input 
                type="date"
                className="w-full mt-1 p-2 rounded-xl bg-slate-50 border border-slate-200 text-sm focus:border-navy-900 focus:outline-none transition-colors"
                value={formData.dueDate}
                onChange={e => setFormData({...formData, dueDate: e.target.value})}
              />
            </div>
            <div>
              <label className="text-xs font-bold text-slate-400 uppercase">Priority</label>
              <select 
                className="w-full mt-1 p-2 rounded-xl bg-slate-50 border border-slate-200 text-sm focus:border-navy-900 focus:outline-none transition-colors"
                value={formData.priority}
                onChange={e => setFormData({...formData, priority: e.target.value as Priority})}
              >
                {Object.values(Priority).map(p => <option key={p} value={p}>{p}</option>)}
              </select>
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
               <label className="text-xs font-bold text-slate-400 uppercase">Project (Optional)</label>
               <select 
                  className="w-full mt-1 p-2 rounded-xl bg-slate-50 border border-slate-200 text-sm focus:border-navy-900 focus:outline-none transition-colors"
                  value={formData.projectId || ''}
                  onChange={e => setFormData({...formData, projectId: e.target.value || undefined})}
               >
                  <option value="">None</option>
                  {projects.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
               </select>
            </div>
            <div>
               <label className="text-xs font-bold text-slate-400 uppercase">Category</label>
               <input 
                  className="w-full mt-1 p-2 rounded-xl bg-slate-50 border border-slate-200 text-sm focus:border-navy-900 focus:outline-none transition-colors"
                  value={formData.category}
                  onChange={e => setFormData({...formData, category: e.target.value})}
                  placeholder="e.g. Work"
               />
            </div>
          </div>

          {/* NOTES SECTION */}
          <div className="bg-slate-50 p-4 rounded-xl border border-slate-100">
             <div className="flex items-center gap-2 mb-2">
                <StickyNote size={14} className="text-navy-900" />
                <label className="text-xs font-bold text-slate-400 uppercase">Notes</label>
             </div>
             <textarea 
                className="w-full p-2 rounded-lg bg-white border border-slate-200 text-sm focus:border-navy-900 focus:outline-none placeholder:text-slate-300 transition-all resize-none h-20"
                placeholder="Add detailed scratchpad notes here..."
                value={formData.notes}
                onChange={e => setFormData({...formData, notes: e.target.value})}
             />
          </div>

          {/* SUBTASKS SECTION */}
          <div className="bg-slate-50 p-4 rounded-xl border border-slate-100">
             <div className="flex items-center gap-2 mb-2">
                <ListCheck size={14} className="text-navy-900" />
                <label className="text-xs font-bold text-slate-400 uppercase">Subtasks</label>
             </div>

             <div className="space-y-2 mb-3">
                {subtasks.map(st => (
                    <div key={st.id} className="flex items-center justify-between bg-white p-2 rounded-lg text-sm border border-slate-100 shadow-sm animate-fade-in">
                        <span className="truncate flex-1 mr-2 text-slate-700">{st.title}</span>
                        <button type="button" onClick={() => removeSubtask(st.id)} className="text-slate-300 hover:text-red-500 transition-colors">
                            <Trash2 size={14}/>
                        </button>
                    </div>
                ))}
             </div>

             <div className="flex gap-2">
                 <input 
                    className="flex-1 p-2 rounded-lg bg-white border border-slate-200 text-sm focus:border-navy-900 focus:outline-none placeholder:text-slate-300 transition-all"
                    placeholder="Add a subtask..."
                    value={newSubtask}
                    onChange={e => setNewSubtask(e.target.value)}
                    onKeyDown={e => e.key === 'Enter' && (e.preventDefault(), addSubtask())}
                 />
                 <button type="button" onClick={addSubtask} className="p-2 bg-white border border-slate-200 rounded-lg hover:border-navy-900 hover:text-navy-900 text-slate-400 transition-colors">
                     <Plus size={18} />
                 </button>
             </div>
          </div>

          {/* ATTACHMENTS SECTION */}
          <div className="bg-slate-50 p-4 rounded-xl border border-slate-100">
             <div className="flex items-center gap-2 mb-2">
                <Paperclip size={14} className="text-navy-900" />
                <label className="text-xs font-bold text-slate-400 uppercase">Attachment (URL)</label>
             </div>
             <div className="flex items-center gap-2 bg-white rounded-lg border border-slate-200 px-3 py-2 focus-within:border-navy-900 transition-colors">
                 <Link size={14} className="text-slate-300" />
                 <input 
                    className="w-full text-sm focus:outline-none placeholder:text-slate-300 text-navy-900"
                    placeholder="e.g., https://drive.google.com/file..."
                    value={attachment}
                    onChange={e => setAttachment(e.target.value)}
                 />
             </div>
          </div>

          <button type="submit" className="w-full bg-navy-900 text-white py-3 rounded-xl font-medium shadow-lg hover:bg-navy-800 transition-all">
            Create Task
          </button>
        </form>
      </div>
    </div>
  );
}

import { Habit, HabitInstance, InterestType, TriggerType, User, ScheduleType, Task, Project } from '../types';
import { formatDate } from '../utils';

// --- MOCK DATABASE SERVICE ---
// Simulates a backend with LocalStorage persistence

class MockDBService {
  private currentUserCache: User | null = null;

  constructor() {}

  // --- SUGGESTION ENGINE ---
  getSuggestions(interests: InterestType[]): Habit[] {
    const SUGGESTED_HABITS: Habit[] = [
        { id: 'h1', name: 'Morning Run (Gym)', icon: 'Activity', interest: InterestType.HEALTH, schedule: ScheduleType.DAILY, triggerType: TriggerType.LOCATION, triggerConfig: { locationName: 'Gold\'s Gym' }, streak: 0 },
        { id: 'h2', name: 'Market Analysis', icon: 'TrendingUp', interest: InterestType.FINANCE, schedule: ScheduleType.WEEKDAYS, triggerType: TriggerType.APP_OPEN, triggerConfig: { appName: 'Market Terminal', actionDetail: 'Check S&P 500' }, streak: 0 },
        { id: 'h3', name: 'Social Media < 30m', icon: 'Smartphone', interest: InterestType.DETOX, schedule: ScheduleType.DAILY, triggerType: TriggerType.SCREEN_TIME, triggerConfig: { thresholdMinutes: 30 }, streak: 0 },
        { id: 'h4', name: 'Read 1 Chapter', icon: 'BookOpen', interest: InterestType.LEARNING, schedule: ScheduleType.DAILY, triggerType: TriggerType.MANUAL, streak: 0 },
        { id: 'h5', name: 'Deep Work Session', icon: 'Zap', interest: InterestType.PRODUCTIVITY, schedule: ScheduleType.WEEKDAYS, triggerType: TriggerType.APP_OPEN, triggerConfig: { appName: 'Timer Started' }, streak: 0 }
    ];

    let suggestions = SUGGESTED_HABITS.filter(h => interests.includes(h.interest));
    if (suggestions.length < 5) {
        const remaining = 5 - suggestions.length;
        const defaults = SUGGESTED_HABITS.filter(h => !suggestions.find(s => s.id === h.id)).slice(0, remaining);
        suggestions = [...suggestions, ...defaults];
    }
    return suggestions.slice(0, 5);
  }

  // --- USER ---

  async getUser(): Promise<User | null> {
    const json = localStorage.getItem('mycore_user');
    if (json) {
        this.currentUserCache = JSON.parse(json);
        return this.currentUserCache;
    }
    return null;
  }

  async initUser(email: string, name: string): Promise<User> {
    const existing = await this.getUser();
    if (existing) return existing;

    const newUser: User = {
      id: 'u_' + Date.now(),
      email,
      name,
      onboarded: false,
      interests: [],
      settings: { locationEnabled: false, notificationsEnabled: false, screenTimeEnabled: false }
    };

    localStorage.setItem('mycore_user', JSON.stringify(newUser));
    this.currentUserCache = newUser;
    return newUser;
  }

  async completeOnboarding(
    userId: string, 
    interests: InterestType[], 
    habits: Habit[], 
    permissions: { loc: boolean; notif: boolean; screen: boolean }
  ): Promise<void> {
    const user = await this.getUser();
    if (!user) return;

    user.onboarded = true;
    user.interests = interests;
    user.settings = {
        locationEnabled: permissions.loc,
        notificationsEnabled: permissions.notif,
        screenTimeEnabled: permissions.screen
    };

    localStorage.setItem('mycore_user', JSON.stringify(user));
    localStorage.setItem('mycore_habits', JSON.stringify(habits));

    // Seed first week
    await this.seedInstancesForWeek(habits);
  }

  async updateUserSettings(settings: User['settings']): Promise<void> {
    if (this.currentUserCache) {
        this.currentUserCache.settings = settings;
        localStorage.setItem('mycore_user', JSON.stringify(this.currentUserCache));
    }
  }

  // --- HABITS ---

  async getHabits(): Promise<Habit[]> {
    const json = localStorage.getItem('mycore_habits');
    const habits: Habit[] = json ? JSON.parse(json) : [];

    const instances = await this.getAllInstances();

    // Recalculate streaks dynamically
    for (const habit of habits) {
        const habitInstances = instances.filter(i => i.habitId === habit.id);
        this.calculateHabitStrength(habit, habitInstances);
    }

    return habits;
  }

  async toggleHabitFavorite(habitId: string): Promise<void> {
    const json = localStorage.getItem('mycore_habits');
    if (!json) return;
    const habits: Habit[] = JSON.parse(json);
    const idx = habits.findIndex(h => h.id === habitId);
    if (idx !== -1) {
        habits[idx].isFavorite = !habits[idx].isFavorite;
        localStorage.setItem('mycore_habits', JSON.stringify(habits));
    }
  }

  private calculateHabitStrength(habit: Habit, instances: HabitInstance[]): void {
    const sorted = [...instances].sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
    let currentStreak = 0;
    const todayStr = formatDate(new Date());

    for (const inst of sorted) {
        if (inst.completed) {
            currentStreak++;
        } else {
             // Allow skipping today if not done yet, but break if yesterday was missed
             if (inst.date === todayStr) continue;
             break; 
        }
    }
    habit.streak = currentStreak;
  }

  // --- INSTANCES ---

  private async getAllInstances(): Promise<HabitInstance[]> {
    const json = localStorage.getItem('mycore_instances');
    return json ? JSON.parse(json) : [];
  }

  async getWeekInstances(dates: string[]): Promise<HabitInstance[]> {
    const allInstances = await this.getAllInstances();
    const habits = await this.getHabits();

    let newInstances: HabitInstance[] = [];
    let hasUpdates = false;

    // Check for missing instances and create them (Lazy Load)
    for (const date of dates) {
        const dayHabits = this.getHabitsForDay(date, habits);
        for (const habit of dayHabits) {
             const exists = allInstances.find(i => i.habitId === habit.id && i.date === date);
             if (!exists) {
                 const newInst: HabitInstance = {
                     id: `${date}_${habit.id}`,
                     habitId: habit.id,
                     date: date,
                     completed: false
                 };
                 allInstances.push(newInst);
                 hasUpdates = true;
             }
        }
    }

    if (hasUpdates) {
        localStorage.setItem('mycore_instances', JSON.stringify(allInstances));
    }

    return allInstances.filter(i => dates.includes(i.date));
  }

  async updateInstanceStatus(instanceId: string, completed: boolean, value?: number): Promise<void> {
    const instances = await this.getAllInstances();
    const idx = instances.findIndex(i => i.id === instanceId);
    if (idx !== -1) {
        instances[idx].completed = completed;
        if (completed) instances[idx].completedAt = new Date().toISOString();
        if (value !== undefined) instances[idx].value = value;
        localStorage.setItem('mycore_instances', JSON.stringify(instances));
    }
  }

  // --- TASKS & PROJECTS ---

  async getTasks(): Promise<Task[]> {
    const json = localStorage.getItem('mycore_tasks');
    return json ? JSON.parse(json) : [];
  }

  async addTask(task: Task): Promise<void> {
    const tasks = await this.getTasks();
    tasks.push(task);
    localStorage.setItem('mycore_tasks', JSON.stringify(tasks));
    if (task.projectId) await this.updateProjectProgress(task.projectId);
  }

  async updateTask(taskId: string, updates: Partial<Task>): Promise<void> {
    const tasks = await this.getTasks();
    const idx = tasks.findIndex(t => t.id === taskId);
    if (idx !== -1) {
        tasks[idx] = { ...tasks[idx], ...updates };
        localStorage.setItem('mycore_tasks', JSON.stringify(tasks));
        if (tasks[idx].projectId) await this.updateProjectProgress(tasks[idx].projectId!);
    }
  }

  async deleteTask(taskId: string): Promise<void> {
    let tasks = await this.getTasks();
    const task = tasks.find(t => t.id === taskId);
    tasks = tasks.filter(t => t.id !== taskId);
    localStorage.setItem('mycore_tasks', JSON.stringify(tasks));
    if (task?.projectId) await this.updateProjectProgress(task.projectId);
  }

  async getProjects(): Promise<Project[]> {
    const json = localStorage.getItem('mycore_projects');
    return json ? JSON.parse(json) : [];
  }

  async addProject(project: Project): Promise<void> {
    const projects = await this.getProjects();
    projects.push(project);
    localStorage.setItem('mycore_projects', JSON.stringify(projects));
  }

  async updateProject(projectId: string, updates: Partial<Project>): Promise<void> {
    const projects = await this.getProjects();
    const idx = projects.findIndex(p => p.id === projectId);
    if (idx !== -1) {
        projects[idx] = { ...projects[idx], ...updates };
        // If progress manually updated, update status
        if (updates.progress !== undefined) {
           projects[idx].status = projects[idx].progress === 100 ? 'completed' : 'active';
        }
        localStorage.setItem('mycore_projects', JSON.stringify(projects));
    }
  }

  async deleteProject(projectId: string): Promise<void> {
    let projects = await this.getProjects();
    projects = projects.filter(p => p.id !== projectId);
    localStorage.setItem('mycore_tasks', JSON.stringify(projects));

    // Clear project ID from tasks
    const tasks = await this.getTasks();
    const updatedTasks = tasks.map(t => t.projectId === projectId ? { ...t, projectId: undefined } : t);
    localStorage.setItem('mycore_tasks', JSON.stringify(updatedTasks));
  }

  private async updateProjectProgress(projectId: string): Promise<void> {
    const tasks = await this.getTasks();
    const projectTasks = tasks.filter(t => t.projectId === projectId);
    const total = projectTasks.length;

    // Only auto-update if there are actually tasks. 
    if (total === 0) return;

    const completed = projectTasks.filter(t => t.completed).length;
    const progress = Math.round((completed / total) * 100);
    const status = progress === 100 ? 'completed' : 'active';

    const projects = await this.getProjects();
    const idx = projects.findIndex(p => p.id === projectId);
    if (idx !== -1) {
        projects[idx].progress = progress;
        projects[idx].status = status;
        localStorage.setItem('mycore_projects', JSON.stringify(projects));
    }
  }

  // --- HELPERS ---

  private getHabitsForDay(dateStr: string, habits: Habit[]): Habit[] {
     const date = new Date(dateStr);
     const dayOfWeek = date.getDay(); // 0 = Sun
     const isWeekend = dayOfWeek === 0 || dayOfWeek === 6;

     return habits.filter(h => {
        if (h.schedule === ScheduleType.DAILY) return true;
        if (h.schedule === ScheduleType.WEEKDAYS) return !isWeekend;
        if (h.schedule === ScheduleType.WEEKENDS) return isWeekend;
        return true;
     });
  }

  private async seedInstancesForWeek(habits: Habit[]) {
     const today = new Date();
     const instances: HabitInstance[] = [];

     // Generate for last 7 days and next 3 days
     for (let i = -7; i <= 3; i++) {
        const d = new Date(today);
        d.setDate(d.getDate() + i);
        const dateStr = formatDate(d);

        const dayHabits = this.getHabitsForDay(dateStr, habits);

        for (const h of dayHabits) {
            instances.push({
                id: `${dateStr}_${h.id}`,
                habitId: h.id,
                date: dateStr,
                completed: false
            });
        }
     }
     localStorage.setItem('mycore_instances', JSON.stringify(instances));
  }

  async reset() {
    localStorage.clear();
    this.currentUserCache = null;
  }
}

export const db = new MockDBService();
